{
  "global": "Open a flight search engine, enter London-to-New York one-way search for 9 May, retrieve results sorted by price, and report the cheapest available fare.",
  "subtasks": [
    {
      "subtask": "Navigate to a flight search engine",
      "atomics": [
        "Open browser and go to a flight comparison site (e.g., Google Flights at flights.google.com)"
      ]
    },
    {
      "subtask": "Enter search parameters",
      "atomics": [
        "Set trip type to one-way",
        "Set origin field to 'London' and select London airports (LHR/LGW/LCY or All London)",
        "Set destination field to 'New York' and select New York airports (JFK/LGA/EWR or All New York)",
        "Set departure date to 9 May 2025"
      ]
    },
    {
      "subtask": "Execute the search",
      "atomics": [
        "Click the Search button and wait for results page to load"
      ]
    },
    {
      "subtask": "Identify the cheapest flight",
      "atomics": [
        "Ensure results are sorted by price ascending (apply 'Cheapest' sort if not default)",
        "Read the price, airline, departure time, and duration of the top-ranked (lowest-price) result"
      ]
    }
  ],
  "global_atomics": [
    "Verify displayed itinerary matches constraints: origin London, destination New York, date 9 May",
    "Record and report the cheapest fare value along with the airline and flight identifier"
  ],
  "gold_actions": {
    "global": "Use Google Flights (flights.google.com) to run a one-way London→New York search on 9 May 2025, sort by price, and extract the lowest fare.",
    "subtasks": [
      {
        "subtask": "Navigate to Google Flights",
        "atomics": [
          "Type 'flights.google.com' in the browser address bar and press Enter"
        ]
      },
      {
        "subtask": "Fill in search form fields",
        "atomics": [
          "Click the trip-type dropdown and select 'One way'",
          "Click the origin input, type 'London', and select 'London (All airports)' from the autocomplete dropdown",
          "Click the destination input, type 'New York', and select 'New York (All airports)' from the autocomplete dropdown",
          "Click the date picker, navigate to May 2025, click day '9', and confirm selection"
        ]
      },
      {
        "subtask": "Submit the search query",
        "atomics": [
          "Click the 'Search' button and wait until the results list renders with at least one fare"
        ]
      },
      {
        "subtask": "Extract the minimum-price itinerary",
        "atomics": [
          "Click 'Price' or 'Cheapest' sort toggle if results are not already price-sorted ascending",
          "Scrape the first result's displayed total price (e.g., '$342'), airline name, and departure/arrival times"
        ]
      }
    ],
    "global_atomics": [
      "Assert that the results header confirms 'London → New York · 9 May · 1 passenger · Economy' before reading the fare",
      "Output the cheapest fare as a structured record: {price, currency, airline, flight_number, departure_time, arrival_time, duration, stops}"
    ]
  }
}
```
